  ('judicial-7acda994-moex-00155', 'judicial-7acda994', 'judicial-7acda994-moex-110-cfe42432', 'sub-judicial-7acda994-05', NULL, 'essay', '以確認處分作為程序標的之行政訴訟繫屬中。依行政訴訟法之規定，法
院得否依職權或依聲請裁定停止強制執行？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:31+00:00", "source_pdf_sha1": "6a824bca392f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "104", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "訴願法與行政訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00156', 'judicial-7acda994', 'judicial-7acda994-moex-110-cfe42432', 'sub-judicial-7acda994-05', NULL, 'essay', '承租國有非公用土地之私人，依國有財產法規定，申請承租轉承購該土
地，經主管機關依一定之計估計價方法決定讓售價格後，通知當事人於
期限內承諾承買。當事人如認價格太高，致無法與機關締結買賣契約，
進而遭主管機關註銷申購，得否提起訴願？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:31+00:00", "source_pdf_sha1": "6a824bca392f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "104", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "訴願法與行政訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00157', 'judicial-7acda994', 'judicial-7acda994-moex-110-cfe42432', 'sub-judicial-7acda994-05', NULL, 'essay', '某公務員因故遭免職之處分，經法院以事屬人事性質之決定，應尊重原
處分之判斷餘地為由而駁回之，以確定終局判決維持原處分。惟該處分
過程諸多瑕疵，所據理由多非事實，於嗣後迭遭確認，並經監察院提出
調查報告公開之。請問在「原免職處分合法有效」之法院確定判決存續
下，機關得否主動重新任命派任該公務員？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:31+00:00", "source_pdf_sha1": "6a824bca392f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "104", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "訴願法與行政訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7acda994-moex-00158', 'judicial-7acda994', 'judicial-7acda994-moex-110-cfe42432', 'sub-judicial-7acda994-05', NULL, 'essay', '某國立大學學生因性騷擾行為，遭學校性別平等教育委員會認定違反性
別平等教育法成立，後經該校依同法第 25 條第 2 項、第 4 項暨學生獎
懲辦法規定，命行為人接受 6 至8 小時心理輔導，並接受 8小時之性別
平等教育相關課程。該生不服，向教育部提起訴願。教育部訴願會經審
查，認該校適用法規、認定事實均有違誤，且所命當事學生應履行之義
務過輕，應加上向被害人道歉、禁止擔任至少一學期之課輔助理等內容，
遂以此為由，撤銷原處分，請原處分機關逕為前述內容之處分。請分析
教育部訴願會之訴願決定是否有違不利益變更禁止之原則？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:31+00:00", "source_pdf_sha1": "6a824bca392f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "104", "s": "0310", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "訴願法與行政訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "行政執行官"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00001', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-114-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲於網路上刊登詐騙廣告，致乙、丙二人受害，損失共計新臺幣 15 萬
元，經地方法院以詐欺罪判處有期徒刑二月。如檢察官僅以量刑過輕為
由提起上訴，惟於二審審理中，另提出尚有丁因本件犯行受害損失新臺
幣 3 萬元事實之移送併辦意旨書，試問：第二審法院對於檢察官請求應
如何處理？（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "7a687f4213df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "410", "s": "0511", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00002', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-114-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲為律師，受詐騙集團首腦乙委任為其成員丙、丁辯護，並受乙諮詢詐
欺罪相關事宜，其後因受乙唆使將偵查中不公開事項轉告於乙，涉犯刑
法第 132 條洩漏國防以外秘密罪，如檢察官聲請搜索甲之律師事務所，
可否扣押甲製作有關甲、乙交談之文件資料？（35 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "7a687f4213df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "410", "s": "0511", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00003', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-114-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '甲犯傷害罪，經一審法院判處有期徒刑一年，甲不服原判決提起上訴，
惟經第二審法院駁回上訴。如甲認原審事實認定錯誤而提起再審救濟，
原參與二審判決之法官乙，得否於再審程序再次參與審判？（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "7a687f4213df", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "410", "s": "0511", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00004', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-113-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '審判中，檢察官提出被告甲在警詢時的自白筆錄及錄音檔案作為證據之
一。在調查證據時，甲爭執筆錄的內容與當日自己的陳述有出入，法官
當庭播放警詢時的錄音檔案，不料發現其品質極差，完全無法分辨是否
為甲的聲音或是其內容為何。試問自白筆錄有無證據能力？請詳述理由
說明。（35 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "2aebff7e989b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "115", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL),
  ('judicial-7b850ce6-moex-00005', 'judicial-7b850ce6', 'judicial-7b850ce6-moex-113-8d1d3a67', 'sub-judicial-7b850ce6-01', NULL, 'essay', '檢察官在偵查結束後，就涉犯殺人未遂罪的嫌疑人甲提起公訴。在審判
中，甲未選任律師為自己辯護，法院也沒有為其指定辯護人。法院審判
後，認檢察官所提出的證據未能證明甲犯罪，諭知無罪判決。檢察官不
服，提起上訴，主張之一是法院未為甲指定辯護人，訴訟程序違法。試
問檢察官的主張是否有理由？請附理由詳細說明。（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:54+00:00", "source_pdf_sha1": "2aebff7e989b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "115", "s": "0510", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "公職法醫師"}'::jsonb, NULL)
